import{_ as s,o as a,c as t,a5 as l}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"概念：系统故障闭环（system fault closure）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：系统故障闭环（system fault closure）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0029-ups-system-fault-closure.html` 的源稿和补充资料。它只使用教学仲裁逻辑和教学故障序列，不包含公司内部系统仲裁策略、未公开产品方案、客户项目参数或内部测试数据。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-system-fault-closure.md","filePath":"content/power/concepts/embedded/ups-system-fault-closure.md","lastUpdated":null}'),i={name:"content/power/concepts/embedded/ups-system-fault-closure.md"};function o(n,e,p,c,r,u){return a(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="概念-系统故障闭环-system-fault-closure" tabindex="-1">概念：系统故障闭环（system fault closure） <a class="header-anchor" href="#概念-系统故障闭环-system-fault-closure" aria-label="Permalink to &quot;概念：系统故障闭环（system fault closure）&quot;">​</a></h1><p>本页是 <code>lessons/0029-ups-system-fault-closure.html</code> 的源稿和补充资料。它只使用教学仲裁逻辑和教学故障序列，不包含公司内部系统仲裁策略、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>系统故障闭环（system fault closure）是把故障锁存（fault latch）、UPS 模式状态机（UPS mode state machine）和输出许可（output permission）连起来：故障锁存后，系统强制进入故障模式并关闭输出；安全复位条件满足后，再允许回到正常模式。</p><p>本节只讲一个概念：故障不是只存在于保护模块里，它必须闭环影响模式和执行器许可。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>如果保护模块已经判定严重故障，但模式状态机仍然停留在在线模式，输出许可仍然打开，那么保护判断就没有真正保护系统。反过来，如果复位条件没有经过统一仲裁，某个模块可能提前恢复输出，造成危险。</p><p>系统闭环的价值是建立一条可审查路径：保护标志 -&gt; 故障锁存 -&gt; 模式强制 -&gt; 输出关闭 -&gt; 安全复位。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>保护标志像发现异常，故障锁存像拉下急停，模式状态机像切换运行牌，输出许可像接触器和 PWM 的允许线。只有这几者串起来，故障才真正进入系统行为。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>latched_fault = FaultLatch(protection_fault, reset_request, safe_to_reset)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if latched_fault:</span></span>
<span class="line"><span>    mode = FAULT</span></span>
<span class="line"><span>    output_permission = all_off</span></span>
<span class="line"><span>else:</span></span>
<span class="line"><span>    mode = ModeStateMachine(input)</span></span>
<span class="line"><span>    output_permission = OutputsFromMode(mode)</span></span></code></pre></div><p>安全复位条件（safe-to-reset condition）不是“按了复位按钮”本身，而是复位请求和安全输入同时满足。</p><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_system_fault_closure.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_system_fault_closure.png</span></span></code></pre></div><p>图中包含保护故障输入、锁存故障、模式码、PFC 许可、逆变 PWM 许可、复位请求和安全复位条件。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>system_step.c</code>：教学系统仲裁层。</li><li><code>UpsSystem_Step()</code>：把故障锁存、模式状态机和输出许可串起来。</li><li><code>UpsFaultLatch_Step()</code>：提供锁存故障状态。</li><li><code>UpsModeStateMachine_Step()</code>：在没有锁存故障时决定模式。</li><li><code>UpsOutputs_FromMode()</code>：把模式和故障锁存变成输出许可。</li></ul><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：保护模块置位后就算保护完成。<br> 正确理解：保护必须影响模式和输出许可，才算闭环。</li><li>错误理解：状态机内部应该直接判断所有采样阈值。<br> 正确理解：更清晰的分层是保护模块判断标志，锁存模块确认故障，系统仲裁层强制模式。</li><li>错误理解：复位只要清锁存即可。<br> 正确理解：复位后还要确认输出许可和模式恢复顺序。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_system_fault_closure.py --no-open</code> 并打开 <code>simulations/results/ups_system_fault_closure.png</code>。</li><li>能解释锁存故障为什么强制模式为 FAULT。</li><li>能解释故障期间 PFC 和逆变 PWM 为什么必须关闭。</li><li>能解释安全复位后为什么才允许 ONLINE 输出许可恢复。</li><li>能基于 <code>system_step.c -&gt; UpsSystem_Step()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>system_step.c -&gt; UpsSystem_Step()</code> 把故障锁存、状态机和输出许可串起来。真实工程里这种系统仲裁层通常集中在哪个任务或模块？</li><li>我用 <code>simulations/results/ups_system_fault_closure.png</code> 看到锁存故障后 PFC 和逆变 PWM 都关闭。真实工程里是否存在故障后部分模块仍允许运行的分级保护？</li><li>我不会记录公司内部系统仲裁策略，只想确认组织方式：真实工程里复位后输出许可恢复是否有固定顺序和延时？</li></ul>`,27)])])}const m=s(i,[["render",o]]);export{h as __pageData,m as default};
